from flask import Flask, request, redirect, session, url_for, jsonify
from urllib.parse import urlencode
import secrets
import requests
import json
import os

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)

# Configuration
OIDC_CONFIG = {
    'authorization_endpoint': os.getenv('OIDC_AUTHORIZATION_ENDPOINT'),
    'token_endpoint': os.getenv('OIDC_TOKEN_ENDPOINT'),
    'userinfo_endpoint': os.getenv('OIDC_USERINFO_ENDPOINT'),
    'issuer': os.getenv('OIDC_ISSUER'),
    'client_id': os.getenv('OIDC_CLIENT_ID'),
    'client_secret': os.getenv('OIDC_CLIENT_SECRET'),
    'redirect_uri': os.getenv('OIDC_REDIRECT_URI'),
    'scopes': 'openid'
}

def get_authorization_url():
    params = {
        'response_type': 'id_token',
        'client_id': OIDC_CONFIG['client_id'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'scope': OIDC_CONFIG['scopes']
    }
    query_string = urlencode(params)
    return f"{OIDC_CONFIG['authorization_endpoint']}?{query_string}"

@app.route('/')
def index():
    if 'access_token' in session:
        return redirect(url_for('dashboard'))
    return '<a href="/login">Login with SSO</a>'

@app.route('/login')
def login():
    auth_url = get_authorization_url()
    return redirect(auth_url)

@app.route('/callback')
def callback():
    id_token = request.args.get('id_token')
    if not id_token:
        return "Authentication failed", 400
    
    # Validate token (basic validation)
    try:
        # Decode JWT (simplified - in production use proper JWT library)
        import base64
        header, payload, signature = id_token.split('.')
        payload += '=' * (4 - len(payload) % 4)
        decoded_payload = base64.b64decode(payload)
        token_data = json.loads(decoded_payload)
        
        # Validate issuer
        if token_data.get('iss') != OIDC_CONFIG['issuer']:
            return "Invalid issuer", 400
            
        # Validate audience
        if token_data.get('aud') != OIDC_CONFIG['client_id']:
            return "Invalid audience", 400
            
        # Validate expiration
        import time
        if token_data.get('exp', 0) < time.time():
            return "Token expired", 400
            
        session['id_token'] = id_token
        session['user_info'] = token_data
        return redirect(url_for('dashboard'))
        
    except Exception as e:
        return f"Token validation failed: {str(e)}", 400

@app.route('/dashboard')
def dashboard():
    if 'id_token' not in session:
        return redirect(url_for('login'))
    
    user_info = session.get('user_info', {})
    return f"""
    <h1>Admin Dashboard</h1>
    <p>Welcome, {user_info.get('sub', 'User')}</p>
    <a href="/logout">Logout</a>
    """

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=False, ssl_context='adhoc' if os.getenv('FORCE_SSL') else None)